import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Question {
  id: number;
  text: string;
  options: {
    key: string;
    text: string;
  }[];
  correctAnswer: string;
}

export interface Student {
  id: number;
  name: string;
}

export type GameStatus = 'IDLE' | 'SPINNING' | 'STUDENT_SELECTED' | 'ANSWERING' | 'CHECKED';

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { STUDENTS, COLORS } from '../constants';

interface SpinWheelProps {
  onSpinEnd: (student: string) => void;
  isSpinning: boolean;
}

const SpinWheel: React.FC<SpinWheelProps> = ({ onSpinEnd, isSpinning }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rotation, setRotation] = useState(0);
  const [targetRotation, setTargetRotation] = useState(0);

  const drawWheel = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const size = canvas.width;
    const centerX = size / 2;
    const centerY = size / 2;
    const radius = size / 2 - 10;
    const sliceAngle = (2 * Math.PI) / STUDENTS.length;

    ctx.clearRect(0, 0, size, size);

    STUDENTS.forEach((student, i) => {
      const angle = i * sliceAngle + rotation;
      ctx.beginPath();
      ctx.fillStyle = COLORS[i % COLORS.length];
      ctx.moveTo(centerX, centerY);
      ctx.arc(centerX, centerY, radius, angle, angle + sliceAngle);
      ctx.lineTo(centerX, centerY);
      ctx.fill();
      ctx.strokeStyle = 'white';
      ctx.lineWidth = 1;
      ctx.stroke();

      // Draw text
      ctx.save();
      ctx.translate(centerX, centerY);
      ctx.rotate(angle + sliceAngle / 2);
      ctx.textAlign = 'right';
      ctx.fillStyle = 'white';
      ctx.font = 'bold 8px Quicksand';
      ctx.fillText(student.name.split(' ').pop() || '', radius - 20, 5);
      ctx.restore();
    });

    // Outer border
    ctx.beginPath();
    ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
    ctx.strokeStyle = '#f59e0b';
    ctx.lineWidth = 5;
    ctx.stroke();

    // Center point
    ctx.beginPath();
    ctx.arc(centerX, centerY, 15, 0, 2 * Math.PI);
    ctx.fillStyle = '#fff';
    ctx.fill();
    ctx.stroke();
  }, [rotation]);

  useEffect(() => {
    drawWheel();
  }, [drawWheel]);

  useEffect(() => {
    if (isSpinning) {
      const extraSpins = 5 + Math.random() * 5;
      const newRotation = targetRotation + (extraSpins * 2 * Math.PI);
      setTargetRotation(newRotation);

      let start: number | null = null;
      const duration = 4000;

      const animate = (time: number) => {
        if (!start) start = time;
        const progress = (time - start) / duration;

        if (progress < 1) {
          // Ease-out cubic
          const easeOut = 1 - Math.pow(1 - progress, 3);
          const currentRot = rotation + (newRotation - rotation) * easeOut;
          setRotation(currentRot);
          requestAnimationFrame(animate);
        } else {
          setRotation(newRotation);
          // Calculate who won
          const sliceAngle = (2 * Math.PI) / STUDENTS.length;
          const normalizedRotation = (newRotation % (2 * Math.PI));
          // The wheel rotation is clockwise. The pointer is at 0 (right).
          // Index = (2PI - rotation) / sliceAngle
          const actualRotation = (2 * Math.PI - normalizedRotation) % (2 * Math.PI);
          const winningIndex = Math.floor(actualRotation / sliceAngle) % STUDENTS.length;
          onSpinEnd(STUDENTS[winningIndex].name);
        }
      };

      requestAnimationFrame(animate);
    }
  }, [isSpinning]);

  return (
    <div className="relative flex flex-col items-center">
      <div className="relative">
        {/* Pointer */}
        <div className="absolute top-1/2 -right-4 -translate-y-1/2 z-10 w-0 h-0 border-t-[15px] border-t-transparent border-b-[15px] border-b-transparent border-r-[25px] border-r-orange-500 shadow-lg"></div>
        <canvas 
          ref={canvasRef} 
          width={400} 
          height={400} 
          className="rounded-full shadow-2xl bg-white"
        />
      </div>
    </div>
  );
};

export default SpinWheel;

import React from 'react';
import { Question } from '../types';

interface QuizProps {
  question: Question;
  selectedOption: string | null;
  onSelectOption: (key: string) => void;
  showFeedback: boolean;
  isCorrect: boolean | null;
}

const Quiz: React.FC<QuizProps> = ({ 
  question, 
  selectedOption, 
  onSelectOption, 
  showFeedback,
  isCorrect 
}) => {
  return (
    <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-yellow-400 min-h-[400px] flex flex-col">
      <div className="flex items-center gap-3 mb-6">
        <span className="bg-orange-500 text-white w-10 h-10 rounded-full flex items-center justify-center font-bold text-xl">
          {question.id}
        </span>
        <h2 className="text-2xl font-bold text-blue-800 leading-tight">
          {question.text}
        </h2>
      </div>

      <div className="space-y-4 flex-grow">
        {question.options.map((option) => (
          <button
            key={option.key}
            onClick={() => !showFeedback && onSelectOption(option.key)}
            className={`w-full text-left p-4 rounded-2xl border-2 transition-all text-lg font-semibold flex items-center gap-4 ${
              selectedOption === option.key
                ? 'bg-blue-100 border-blue-500 text-blue-900'
                : 'bg-gray-50 border-gray-200 text-gray-700 hover:bg-yellow-50 hover:border-yellow-300'
            } ${
              showFeedback && option.key === question.correctAnswer
                ? 'bg-green-100 border-green-500 !text-green-800'
                : ''
            } ${
              showFeedback && selectedOption === option.key && option.key !== question.correctAnswer
                ? 'bg-red-100 border-red-500 !text-red-800'
                : ''
            }`}
            disabled={showFeedback}
          >
            <span className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${
              selectedOption === option.key ? 'bg-blue-500 text-white border-blue-500' : 'bg-white border-gray-300 text-gray-500'
            }`}>
              {option.key}
            </span>
            {option.text}
          </button>
        ))}
      </div>

      {showFeedback && (
        <div className={`mt-6 p-4 rounded-2xl text-center animate-bounce font-bold text-2xl ${
          isCorrect ? 'bg-green-500 text-white' : 'bg-red-500 text-white'
        }`}>
          {isCorrect ? '🎉 Rất giỏi! Chúc mừng em!' : '💪 Em cố gắng hơn nhé!'}
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useCallback } from 'react';
import SpinWheel from './components/SpinWheel';
import Quiz from './components/Quiz';
import { QUESTIONS } from './constants';
import { GameStatus } from './types';
import { Star, Trophy, Sparkles, RefreshCcw, CheckCircle, Play } from 'lucide-react';

const App: React.FC = () => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedStudent, setSelectedStudent] = useState<string | null>(null);
  const [gameStatus, setGameStatus] = useState<GameStatus>('IDLE');
  const [userAnswer, setUserAnswer] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const currentQuestion = QUESTIONS[currentQuestionIndex];

  const handleStartSpin = () => {
    if (gameStatus === 'SPINNING') return;
    setGameStatus('SPINNING');
    setSelectedStudent(null);
    setShowFeedback(false);
    setUserAnswer(null);
  };

  const handleSpinEnd = (student: string) => {
    setSelectedStudent(student);
    setGameStatus('STUDENT_SELECTED');
  };

  const handleSelectOption = (key: string) => {
    setUserAnswer(key);
    setGameStatus('ANSWERING');
  };

  const handleCheckResult = () => {
    if (!userAnswer) return;
    setShowFeedback(true);
    setGameStatus('CHECKED');
  };

  const handleNextTurn = () => {
    setGameStatus('IDLE');
    setSelectedStudent(null);
    setUserAnswer(null);
    setShowFeedback(false);
    // Loop questions
    setCurrentQuestionIndex((prev) => (prev + 1) % QUESTIONS.length);
  };

  const isCorrect = userAnswer === currentQuestion.correctAnswer;

  return (
    <div className="min-h-screen bg-[#fef9c3] p-4 md:p-8 flex flex-col items-center">
      {/* Decorative elements */}
      <div className="fixed top-10 left-10 text-yellow-500 animate-float opacity-50"><Star size={48} fill="currentColor" /></div>
      <div className="fixed bottom-10 right-10 text-blue-400 animate-float opacity-50" style={{animationDelay: '1s'}}><Sparkles size={48} /></div>
      <div className="fixed top-40 right-20 text-red-400 animate-float opacity-50" style={{animationDelay: '0.5s'}}><Trophy size={48} /></div>

      <header className="mb-8 text-center relative z-10">
        <h1 className="text-5xl md:text-6xl font-black text-blue-700 tracking-tight drop-shadow-md mb-2 flex items-center justify-center gap-4">
          <Star className="text-yellow-500 fill-yellow-500" />
          VÒNG QUAY MAY MẮN
          <Star className="text-yellow-500 fill-yellow-500" />
        </h1>
        <p className="text-xl font-bold text-orange-600 bg-white/50 inline-block px-4 py-1 rounded-full border-2 border-orange-200 shadow-sm">
          Trò chơi học tập tương tác cho bé lớp 2
        </p>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-2 gap-8 items-start relative z-10">
        {/* Left Side: Quiz */}
        <div className="order-2 lg:order-1">
          <Quiz 
            question={currentQuestion}
            selectedOption={userAnswer}
            onSelectOption={handleSelectOption}
            showFeedback={showFeedback}
            isCorrect={isCorrect}
          />
        </div>

        {/* Right Side: Spin Wheel */}
        <div className="order-1 lg:order-2 flex flex-col items-center">
          <div className="mb-6 min-h-[80px] text-center w-full">
            {selectedStudent ? (
              <div className="animate-bounce inline-block">
                <span className="text-sm font-bold text-blue-500 block uppercase mb-1">Học sinh được chọn là:</span>
                <span className="text-4xl font-black text-white bg-red-500 px-6 py-2 rounded-2xl shadow-xl border-4 border-yellow-300 inline-block">
                  {selectedStudent}
                </span>
              </div>
            ) : gameStatus === 'SPINNING' ? (
              <span className="text-2xl font-bold text-orange-500 animate-pulse">Vòng quay đang xoay...</span>
            ) : (
              <span className="text-2xl font-bold text-gray-400 italic">Nhấn "Bắt đầu quay" để chọn học sinh!</span>
            )}
          </div>
          <SpinWheel onSpinEnd={handleSpinEnd} isSpinning={gameStatus === 'SPINNING'} />
        </div>
      </main>

      {/* Footer Controls */}
      <footer className="mt-12 mb-8 flex flex-wrap justify-center gap-6 relative z-10">
        <button
          onClick={handleStartSpin}
          disabled={gameStatus === 'SPINNING' || gameStatus === 'CHECKED'}
          className="group flex items-center gap-3 bg-gradient-to-br from-yellow-400 to-orange-500 text-white px-8 py-4 rounded-full font-black text-2xl shadow-[0_8px_0_rgb(194,120,0)] active:shadow-none active:translate-y-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:brightness-110"
        >
          <Play className="fill-white" />
          Bắt đầu quay
        </button>

        <button
          onClick={handleCheckResult}
          disabled={!userAnswer || gameStatus === 'CHECKED'}
          className="group flex items-center gap-3 bg-gradient-to-br from-blue-400 to-blue-600 text-white px-8 py-4 rounded-full font-black text-2xl shadow-[0_8px_0_rgb(29,78,216)] active:shadow-none active:translate-y-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:brightness-110"
        >
          <CheckCircle />
          Kiểm tra KQ
        </button>

        <button
          onClick={handleNextTurn}
          disabled={gameStatus !== 'CHECKED'}
          className="group flex items-center gap-3 bg-gradient-to-br from-green-400 to-green-600 text-white px-8 py-4 rounded-full font-black text-2xl shadow-[0_8px_0_rgb(21,128,61)] active:shadow-none active:translate-y-2 transition-all disabled:opacity-50 disabled:cursor-not-allowed hover:brightness-110"
        >
          <RefreshCcw className="group-hover:rotate-180 transition-transform duration-500" />
          Chơi tiếp
        </button>
      </footer>

      {/* Visual background clutter */}
      <div className="absolute top-1/4 left-1/4 w-12 h-12 bg-pink-200 rounded-full blur-xl opacity-40"></div>
      <div className="absolute bottom-1/4 right-1/4 w-20 h-20 bg-blue-200 rounded-full blur-xl opacity-40"></div>
    </div>
  );
};

export default App;

